sql:
SELECT COUNT(*) AS number_of_companies
FROM companies
WHERE industry = 'Media';

external_knowledge:
- Significant deviation: Absolute difference greater than 100;
- Recent trend: Calculated using a 30-day moving average;
- Notable fluctuation: Indicates a substantial change in the stock price relative to its recent performance.

sql:
SELECT company_name, market_price
FROM companies
JOIN market_data ON companies.company_id = market_data.company_id;

